/* Global styles for M3ssag1n8 */

*, *::before, *::after {
  box-sizing: border-box;
}

html, body {
  margin: 0;
  padding: 0;
  height: 100%;
  font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
  background: #24273a;
  color: #cdd6f4;
}

/* Login Modal */
.login-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.5);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.login-backdrop.hidden { display: none !important; }

.login-modal {
  background: #1e1e2e;
  color: #cdd6f4;
  border-radius: 12px;
  padding: 2rem;
  width: 340px;
  max-width: 90vw;
  box-shadow: 0 8px 32px rgba(0,0,0,0.6);
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.login-modal h2 {
  margin: 0 0 0.5rem;
  font-size: 1.4rem;
  color: #89b4fa;
  text-align: center;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
}

.login-modal label { font-size: 0.85rem; color: #6c7086; }

.login-modal input {
  padding: 0.6rem 0.8rem;
  border: 1px solid #45475a;
  border-radius: 6px;
  background: #313244;
  color: #cdd6f4;
  font-size: 1rem;
  outline: none;
  font-family: inherit;
}

.login-modal input:focus { border-color: #89b4fa; }

.login-modal button {
  padding: 0.6rem 1rem;
  border: none;
  border-radius: 6px;
  background: #89b4fa;
  color: #1e1e2e;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
}

.login-modal button:hover { background: #74c7ec; }

.login-error {
  color: #f38ba8;
  font-size: 0.85rem;
  text-align: center;
  min-height: 1.2em;
  margin: 0;
}

/* App layout */
.app-blurred {
  filter: blur(2px);
  pointer-events: none;
  user-select: none;
  height: 100vh;
  display: flex;
  flex-direction: column;
}

.app-blurred.active {
  filter: none;
  pointer-events: auto;
  user-select: auto;
}

#app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 1rem;
  height: 50px;
  background: #1e1e2e;
  border-bottom: 2px solid #313244;
  flex-shrink: 0;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: #89b4fa;
  font-size: 1.2rem;
}

.app-title { font-size: 1.2rem; font-weight: 700; color: #cba6f7; }

.header-right { display: flex; align-items: center; gap: 0.75rem; }

.username { font-weight: 600; color: #a6e3a1; font-size: 0.9rem; }

#logout-btn {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  padding: 0.3rem 0.75rem;
  background: #f38ba8;
  color: #1e1e2e;
  border: none;
  border-radius: 5px;
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
}

#logout-btn:hover { background: #eba0ac; }

#main-content {
  display: flex;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

/* Sidebars */
.sidebar {
  display: flex;
  flex-direction: column;
  background: #181825;
  min-width: 200px;
  width: 200px;
  border-right: 1px solid #313244;
  padding: 0.75rem;
  gap: 0.4rem;
  overflow-y: auto;
  flex-shrink: 0;
}

.sidebar-title {
  margin: 0 0 0.2rem;
  font-size: 0.82rem;
  color: #89b4fa;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: 700;
}

.sidebar-workspace-name {
  font-size: 0.92rem;
  font-weight: 700;
  color: #cba6f7;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-controls { display: flex; flex-direction: column; gap: 0.3rem; }

.sidebar-controls input {
  padding: 0.35rem 0.5rem;
  border: 1px solid #45475a;
  border-radius: 5px;
  background: #313244;
  color: #cdd6f4;
  font-size: 0.82rem;
  outline: none;
  font-family: inherit;
  width: 100%;
}

.sidebar-controls input:focus { border-color: #89b4fa; }

.btn-group { display: flex; gap: 0.25rem; }
.btn-group button { flex: 1; }

button {
  font-family: inherit;
  cursor: pointer;
  border: none;
  border-radius: 5px;
  font-size: 0.75rem;
  padding: 0.3rem 0.5rem;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 0.2rem;
  justify-content: center;
}

button:hover { opacity: 0.85; }

.btn-primary { background: #89b4fa; color: #1e1e2e; }
.btn-success { background: #a6e3a1; color: #1e1e2e; }
.btn-danger  { background: #f38ba8; color: #1e1e2e; }
.btn-secondary { background: #45475a; color: #cdd6f4; width: 100%; }

.panel-error {
  color: #f38ba8;
  font-size: 0.78rem;
  padding: 0.3rem 0.5rem;
  background: #3b1c2c;
  border-radius: 5px;
  display: flex;
  align-items: flex-start;
  gap: 0.3rem;
}

.dismiss-btn {
  background: none !important;
  color: #f38ba8 !important;
  padding: 0 !important;
  font-size: 1rem !important;
  flex-shrink: 0;
  font-weight: 700;
  border: none;
  cursor: pointer;
  line-height: 1;
}

.item-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.2rem;
}

.workspace-item, .channel-item {
  padding: 0.33rem 0.5rem;
  border-radius: 4px;
  cursor: pointer;
  background: #313244;
  font-size: 0.82rem;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: background 0.12s;
}

.workspace-item:hover, .channel-item:hover { background: #45475a; }
.workspace-item.active { background: #89b4fa; color: #1e1e2e; font-weight: 700; }
.channel-item.active   { background: #cba6f7; color: #1e1e2e; font-weight: 700; }

/* Post section */
#post-section {
  display: flex;
  flex-direction: column;
  flex: 1;
  background: #24273a;
  min-width: 0;
  overflow: hidden;
}

.post-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.75rem 1rem;
  border-bottom: 1px solid #313244;
  font-size: 1.05rem;
  font-weight: 600;
  color: #cba6f7;
  flex-shrink: 0;
  background: #1e1e2e;
}

.post-list {
  flex: 1;
  overflow-y: auto;
  padding: 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  min-height: 0;
}

.post-item {
  background: #1e1e2e;
  border-radius: 8px;
  padding: 0.75rem 1rem;
}

.post-item .replies {
  margin-top: 0.5rem;
  margin-left: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.post-item .replies .post-item {
  background: #181825;
  border-left: 2px solid #45475a;
  border-radius: 0 6px 6px 0;
}

.post-header-row {
  display: flex;
  align-items: baseline;
  gap: 0.5rem;
  margin-bottom: 0.33rem;
}

.post-author { font-weight: 700; color: #89b4fa; font-size: 0.87rem; }
.post-time   { color: #6c7086; font-size: 0.72rem; }

.post-content {
  font-size: 0.87rem;
  line-height: 1.55;
  color: #cdd6f4;
  word-break: break-word;
}

.post-content a { color: #89b4fa; text-decoration: underline; }

.post-actions {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 0.3rem;
  margin-top: 0.45rem;
}

.reply-btn {
  background: none;
  border: 1px solid #45475a;
  color: #6c7086;
  border-radius: 4px;
  padding: 0.16rem 0.4rem;
  font-size: 0.72rem;
  cursor: pointer;
  font-family: inherit;
}

.reply-btn:hover { color: #cdd6f4; border-color: #89b4fa; }

.reaction-btn {
  display: inline-flex;
  align-items: center;
  gap: 0.18rem;
  background: #313244;
  border: 1px solid #45475a;
  color: #cdd6f4;
  border-radius: 4px;
  padding: 0.16rem 0.4rem;
  font-size: 0.72rem;
  cursor: pointer;
  font-family: inherit;
}

.reaction-btn:hover { background: #45475a; }
.reaction-btn.reacted { background: #45475a; border-color: #89b4fa; color: #89b4fa; }
.reaction-count { font-weight: 700; }

/* Post input */
.post-input-area {
  padding: 0.75rem 1rem;
  border-top: 1px solid #313244;
  background: #1e1e2e;
  flex-shrink: 0;
}

.reply-context {
  font-size: 0.8rem;
  color: #6c7086;
  margin-bottom: 0.4rem;
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.close-reply-btn {
  background: none !important;
  border: none;
  color: #f38ba8 !important;
  cursor: pointer;
  font-size: 0.8rem;
  padding: 0;
  font-weight: 600;
  font-family: inherit;
}

.format-btns {
  display: flex;
  gap: 0.3rem;
  margin-bottom: 0.4rem;
  flex-wrap: wrap;
}

.fmt-btn {
  background: #313244;
  border: 1px solid #45475a;
  color: #cdd6f4;
  border-radius: 4px;
  padding: 0.16rem 0.45rem;
  font-size: 0.75rem;
  cursor: pointer;
  font-family: inherit;
}

.fmt-btn:hover { background: #45475a; }

.input-row { display: flex; gap: 0.5rem; align-items: flex-end; }

#post-input {
  flex: 1;
  padding: 0.5rem 0.75rem;
  background: #313244;
  border: 1px solid #45475a;
  border-radius: 6px;
  color: #cdd6f4;
  font-size: 0.88rem;
  resize: none;
  min-height: 2.5rem;
  max-height: 8rem;
  outline: none;
  font-family: inherit;
}

#post-input:focus { border-color: #89b4fa; }

.btn-post {
  background: #89b4fa;
  color: #1e1e2e;
  border-radius: 6px;
  padding: 0.5rem 1rem;
  font-size: 0.9rem;
  font-weight: 700;
  white-space: nowrap;
  border: none;
  cursor: pointer;
  font-family: inherit;
  flex-shrink: 0;
}

.btn-post:hover { background: #74c7ec; }

.empty-state {
  color: #6c7086;
  text-align: center;
  padding: 2rem;
  font-style: italic;
}

.hidden { display: none !important; }

::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: #1e1e2e; }
::-webkit-scrollbar-thumb { background: #45475a; border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: #6c7086; }

/**
 * Application state management using a simple pub/sub EventTarget store.
 */

import { Post, Workspace, Channel } from "./types";
import { SSEPostEvent, subscribeToChannel } from "./api";
import { slog } from "./slog";

// ---------------------------------------------------------------------------
// State shape
// ---------------------------------------------------------------------------

export interface AppState {
  /** Currently logged-in username, null if not logged in. */
  username: string | null;
  /** Bearer token for API calls. */
  token: string | null;
  /** All known workspaces. */
  workspaces: Workspace[];
  /** Name of the currently open workspace. */
  currentWorkspace: string | null;
  /** Channels in the currently open workspace. */
  channels: Channel[];
  /** Name of the currently open channel. */
  currentChannel: string | null;
  /** Posts in the currently open channel (live via SSE). */
  posts: Map<string, Post>;
  /** Global error message (null = no error). */
  error: string | null;
  /** Path of the post being replied to (null = top-level). */
  replyTo: string | null;
}

// ---------------------------------------------------------------------------
// Store
// ---------------------------------------------------------------------------

class AppStore extends EventTarget {
  private _state: AppState = {
    username: null,
    token: null,
    workspaces: [],
    currentWorkspace: null,
    channels: [],
    currentChannel: null,
    posts: new Map(),
    error: null,
    replyTo: null,
  };

  /** Current state snapshot. */
  get state(): Readonly<AppState> {
    return this._state;
  }

  /** Update state and notify listeners. */
  setState(update: Partial<AppState>): void {
    this._state = { ...this._state, ...update };
    this.dispatchEvent(new CustomEvent("state-change", { detail: this._state }));
  }

  /** Convenience: set error. */
  setError(msg: string | null): void {
    this.setState({ error: msg });
  }

  /** Clear error. */
  clearError(): void {
    this.setState({ error: null });
  }
}

export const store = new AppStore();

// ---------------------------------------------------------------------------
// SSE subscription management
// ---------------------------------------------------------------------------

let sseController: AbortController | null = null;

/** Start SSE subscription for the given channel. Cancels any prior subscription. */
export function startChannelSubscription(workspace: string, channel: string): void {
  stopChannelSubscription();

  const { token } = store.state;
  if (!token) return;

  sseController = subscribeToChannel(
    token,
    workspace,
    channel,
    (event: SSEPostEvent) => handleSSEEvent(event),
    (err) => slog.warn("SSE error in channel subscription", ["err", err]),
  );
}

/** Stop the current SSE subscription. */
export function stopChannelSubscription(): void {
  if (sseController) {
    sseController.abort();
    sseController = null;
  }
}

function handleSSEEvent(event: SSEPostEvent): void {
  const { posts } = store.state;
  const newPosts = new Map(posts);

  if (event.eventType === "delete") {
    newPosts.delete(event.path);
  } else if (event.doc && event.meta) {
    // put or patch — upsert the post
    newPosts.set(event.path, {
      path: event.path,
      doc: event.doc,
      meta: event.meta,
    });
  } else if (event.eventType === "put" && event.doc) {
    // put without meta — create with empty meta
    newPosts.set(event.path, {
      path: event.path,
      doc: event.doc,
      meta: { createdAt: "", createdBy: "" },
    });
  } else if (event.eventType === "patch" && event.doc) {
    // patch — merge into existing
    const existing = newPosts.get(event.path);
    if (existing) {
      newPosts.set(event.path, {
        ...existing,
        doc: { ...existing.doc, ...event.doc },
      });
    } else {
      newPosts.set(event.path, {
        path: event.path,
        doc: event.doc,
        meta: { createdAt: "", createdBy: "" },
      });
    }
  }

  store.setState({ posts: newPosts });
}

/** Reset posts and close the current channel. */
export function closeChannel(): void {
  stopChannelSubscription();
  store.setState({ currentChannel: null, posts: new Map(), replyTo: null });
}

/** Reset everything related to workspace/channel when workspace closes. */
export function closeWorkspace(): void {
  closeChannel();
  store.setState({ currentWorkspace: null, channels: [] });
}

/** Reset all state on logout. */
export function resetState(): void {
  stopChannelSubscription();
  store.setState({
    username: null,
    token: null,
    workspaces: [],
    currentWorkspace: null,
    channels: [],
    currentChannel: null,
    posts: new Map(),
    error: null,
    replyTo: null,
  });
}

/**
 * M3ssag1n8 — main application entry point.
 * All UI logic wired here; elements are in the light DOM (index.html).
 */

import { slog } from "./slog";
import { store, resetState, startChannelSubscription, closeChannel, closeWorkspace } from "./state";
import {
  login,
  logout,
  listWorkspaces,
  createWorkspace as apiCreateWorkspace,
  openWorkspace as apiOpenWorkspace,
  deleteWorkspace as apiDeleteWorkspace,
  listChannels,
  createChannel as apiCreateChannel,
  openChannel as apiOpenChannel,
  deleteChannel as apiDeleteChannel,
  createPost as apiCreatePost,
  patchReactions,
} from "./api";
import { renderMarkdown, formatTime } from "./markdown";
import { Post } from "./types";

declare const process: {
  env: { DATABASE_HOST: string; DATABASE_PATH: string; AUTH_PATH: string };
};

// ---------------------------------------------------------------------------
// Reaction config
// ---------------------------------------------------------------------------

const REACTIONS = [
  { key: ":smile:",     icon: "mdi:emoticon-happy-outline", label: "smile"     },
  { key: ":frown:",     icon: "mdi:emoticon-sad-outline",   label: "frown"     },
  { key: ":like:",      icon: "mdi:thumb-up-outline",       label: "like"      },
  { key: ":celebrate:", icon: "mdi:party-popper",           label: "celebrate" },
];

// ---------------------------------------------------------------------------
// Current reply target
// ---------------------------------------------------------------------------

let replyToPath: string | null = null;

// ---------------------------------------------------------------------------
// DOM helpers (typed getters — all elements are in index.html light DOM)
// ---------------------------------------------------------------------------

const $ = <T extends HTMLElement>(id: string) =>
  document.getElementById(id) as T;

// ---------------------------------------------------------------------------
// Main entry
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  slog.info("M3ssag1n8 starting", [
    "db",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  setupLogin();
  setupWorkspaces();
  setupChannels();
  setupPosts();
  subscribeToStateChanges();

  // Show login on startup
  showLoginModal();
}

// ---------------------------------------------------------------------------
// Login / Logout
// ---------------------------------------------------------------------------

function showLoginModal(): void {
  $("login-backdrop").classList.remove("hidden");
  const app = $("app");
  app.classList.remove("active");
  app.classList.add("app-blurred");
  app.setAttribute("aria-hidden", "true");
  const usernameInput = $<HTMLInputElement>("username-input");
  usernameInput.value = "";
  $("login-error").textContent = "";
  usernameInput.focus();
}

function hideLoginModal(): void {
  $("login-backdrop").classList.add("hidden");
  const app = $("app");
  app.classList.remove("app-blurred");
  app.classList.add("active");
  app.removeAttribute("aria-hidden");
}

function setupLogin(): void {
  const usernameInput = $<HTMLInputElement>("username-input");
  const loginBtn = $<HTMLButtonElement>("login-btn");

  const doLogin = async (): Promise<void> => {
    const username = usernameInput.value.trim();
    if (!username) {
      $("login-error").textContent = "Please enter a username.";
      return;
    }
    $("login-error").textContent = "";
    loginBtn.disabled = true;
    try {
      const token = await login(username);
      store.setState({ username, token });
      $("current-username").textContent = username;
      hideLoginModal();
      await loadWorkspaces();
    } catch (e) {
      $("login-error").textContent = e instanceof Error ? e.message : "Login failed";
    } finally {
      loginBtn.disabled = false;
    }
  };

  loginBtn.addEventListener("click", doLogin);
  usernameInput.addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter") doLogin();
  });

  $<HTMLButtonElement>("logout-btn").addEventListener("click", async () => {
    const { token } = store.state;
    if (token) {
      try { await logout(token); } catch { /* ignore */ }
    }
    resetState();
    $("current-username").textContent = "";
    showLoginModal();
  });
}

// ---------------------------------------------------------------------------
// Workspaces
// ---------------------------------------------------------------------------

function showWsError(msg: string): void {
  const errDiv = $("ws-error");
  errDiv.classList.remove("hidden");
  $("ws-error-msg").textContent = msg;
}

function clearWsError(): void {
  $("ws-error").classList.add("hidden");
}

function setupWorkspaces(): void {
  $<HTMLButtonElement>("open-workspace-btn").addEventListener("click", () =>
    handleOpenWorkspace(),
  );
  $<HTMLButtonElement>("create-workspace-btn").addEventListener("click", () =>
    handleCreateWorkspace(),
  );
  $<HTMLButtonElement>("delete-workspace-btn").addEventListener("click", () =>
    handleDeleteWorkspace(),
  );
  $<HTMLButtonElement>("refresh-workspaces-btn").addEventListener("click", () =>
    loadWorkspaces(),
  );
  $("ws-dismiss-error").addEventListener("click", () => clearWsError());
  $<HTMLInputElement>("workspace-name-input").addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter") handleOpenWorkspace();
  });
}

async function loadWorkspaces(): Promise<void> {
  const { token } = store.state;
  if (!token) return;
  try {
    const workspaces = await listWorkspaces(token);
    store.setState({ workspaces });
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error loading workspaces");
  }
}

async function handleOpenWorkspace(): Promise<void> {
  const name = $<HTMLInputElement>("workspace-name-input").value.trim();
  if (!name) return;
  clearWsError();
  const { token } = store.state;
  if (!token) return;
  try {
    const channels = await apiOpenWorkspace(token, name);
    closeWorkspace();
    store.setState({ currentWorkspace: name, channels });
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error opening workspace");
  }
}

async function handleCreateWorkspace(): Promise<void> {
  const name = $<HTMLInputElement>("workspace-name-input").value.trim();
  if (!name) return;
  clearWsError();
  const { token } = store.state;
  if (!token) return;
  try {
    await apiCreateWorkspace(token, name);
    const channels = await apiOpenWorkspace(token, name);
    closeWorkspace();
    store.setState({ currentWorkspace: name, channels });
    await loadWorkspaces();
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error creating workspace");
  }
}

async function handleDeleteWorkspace(): Promise<void> {
  const name = $<HTMLInputElement>("workspace-name-input").value.trim();
  if (!name) return;
  clearWsError();
  const { token } = store.state;
  if (!token) return;
  try {
    await apiDeleteWorkspace(token, name);
    closeWorkspace();
    await loadWorkspaces();
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error deleting workspace");
  }
}

function renderWorkspaceList(): void {
  const { workspaces, currentWorkspace } = store.state;
  const list = $("workspace-list");
  list.innerHTML = "";
  for (const ws of workspaces) {
    const li = document.createElement("li");
    li.className = "workspace-item" + (ws.name === currentWorkspace ? " active" : "");
    li.textContent = ws.name;
    li.title = ws.name;
    li.addEventListener("click", () => {
      $<HTMLInputElement>("workspace-name-input").value = ws.name;
      handleOpenWorkspace();
    });
    list.appendChild(li);
  }
}

// ---------------------------------------------------------------------------
// Channels
// ---------------------------------------------------------------------------

function showChError(msg: string): void {
  const errDiv = $("ch-error");
  errDiv.classList.remove("hidden");
  $("ch-error-msg").textContent = msg;
}

function clearChError(): void {
  $("ch-error").classList.add("hidden");
}

function setupChannels(): void {
  $<HTMLButtonElement>("open-channel-btn").addEventListener("click", () =>
    handleOpenChannel(),
  );
  $<HTMLButtonElement>("create-channel-btn").addEventListener("click", () =>
    handleCreateChannel(),
  );
  $<HTMLButtonElement>("delete-channel-btn").addEventListener("click", () =>
    handleDeleteChannel(),
  );
  $<HTMLButtonElement>("refresh-channels-btn").addEventListener("click", () =>
    loadChannels(),
  );
  $("ch-dismiss-error").addEventListener("click", () => clearChError());
  $<HTMLInputElement>("channel-name-input").addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter") handleOpenChannel();
  });
}

async function loadChannels(): Promise<void> {
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    const channels = await listChannels(token, currentWorkspace);
    store.setState({ channels });
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error loading channels");
  }
}

async function handleOpenChannel(): Promise<void> {
  const name = $<HTMLInputElement>("channel-name-input").value.trim();
  if (!name) return;
  clearChError();
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    await apiOpenChannel(token, currentWorkspace, name);
    closeChannel();
    store.setState({ currentChannel: name });
    startChannelSubscription(currentWorkspace, name);
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error opening channel");
  }
}

async function handleCreateChannel(): Promise<void> {
  const name = $<HTMLInputElement>("channel-name-input").value.trim();
  if (!name) return;
  clearChError();
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    await apiCreateChannel(token, currentWorkspace, name);
    closeChannel();
    store.setState({ currentChannel: name });
    startChannelSubscription(currentWorkspace, name);
    await loadChannels();
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error creating channel");
  }
}

async function handleDeleteChannel(): Promise<void> {
  const name = $<HTMLInputElement>("channel-name-input").value.trim();
  if (!name) return;
  clearChError();
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    await apiDeleteChannel(token, currentWorkspace, name);
    closeChannel();
    await loadChannels();
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error deleting channel");
  }
}

function renderChannelList(): void {
  const { channels, currentChannel } = store.state;
  const list = $("channel-list");
  list.innerHTML = "";
  for (const ch of channels) {
    const li = document.createElement("li");
    li.className = "channel-item" + (ch.name === currentChannel ? " active" : "");
    li.textContent = ch.name;
    li.title = ch.name;
    li.addEventListener("click", () => {
      $<HTMLInputElement>("channel-name-input").value = ch.name;
      handleOpenChannel();
    });
    list.appendChild(li);
  }
}

// ---------------------------------------------------------------------------
// Posts
// ---------------------------------------------------------------------------

function setupPosts(): void {
  const submitBtn = $<HTMLButtonElement>("post-submit-btn");
  const postInput = $<HTMLTextAreaElement>("post-input");
  const closeReplyBtn = $<HTMLButtonElement>("close-reply-btn");
  const fmtBold = $<HTMLButtonElement>("fmt-bold");
  const fmtItalic = $<HTMLButtonElement>("fmt-italic");
  const fmtLink = $<HTMLButtonElement>("fmt-link");

  submitBtn.addEventListener("click", () => handleCreatePost());

  postInput.addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleCreatePost();
    }
  });

  closeReplyBtn.addEventListener("click", () => cancelReply());

  fmtBold.addEventListener("click", () =>
    insertFormat(postInput, "**", "**", "bold text"),
  );
  fmtItalic.addEventListener("click", () =>
    insertFormat(postInput, "*", "*", "italic text"),
  );
  fmtLink.addEventListener("click", () =>
    insertFormat(postInput, "[", "](https://example.com)", "link text"),
  );

  document.querySelectorAll<HTMLButtonElement>(".reaction-insert").forEach((btn) => {
    btn.addEventListener("click", () => {
      const reaction = btn.dataset["reaction"] ?? "";
      insertAtCursor(postInput, reaction);
    });
  });
}

function insertFormat(
  textarea: HTMLTextAreaElement,
  before: string,
  after: string,
  placeholder: string,
): void {
  const start = textarea.selectionStart;
  const end = textarea.selectionEnd;
  const selected = textarea.value.substring(start, end) || placeholder;
  textarea.setRangeText(`${before}${selected}${after}`, start, end, "end");
  textarea.focus();
}

function insertAtCursor(textarea: HTMLTextAreaElement, text: string): void {
  const start = textarea.selectionStart;
  const end = textarea.selectionEnd;
  textarea.setRangeText(text, start, end, "end");
  textarea.focus();
}

async function handleCreatePost(): Promise<void> {
  const input = $<HTMLTextAreaElement>("post-input");
  const msg = input.value;
  if (!msg.trim()) return;

  const { token, currentWorkspace, currentChannel } = store.state;
  if (!token || !currentWorkspace || !currentChannel) return;

  try {
    await apiCreatePost(token, currentWorkspace, currentChannel, msg, replyToPath ?? "");
    input.value = "";
    cancelReply();
  } catch (e) {
    slog.warn("Failed to create post", ["error", e]);
  }
}

function startReply(postPath: string, postMsg: string): void {
  replyToPath = postPath;
  const ctx = $("reply-context");
  ctx.classList.remove("hidden");
  const preview = postMsg.length > 40 ? postMsg.substring(0, 40) + "…" : postMsg;
  $("reply-context-text").textContent = `Replying to: "${preview}"`;

  // Move input area to appear after the post being replied to
  const postEl = document.querySelector(`[data-path="${CSS.escape(postPath)}"]`);
  const inputArea = $("post-input-area");
  if (postEl) {
    postEl.after(inputArea);
  }
  $<HTMLTextAreaElement>("post-input").focus();
}

function cancelReply(): void {
  replyToPath = null;
  $("reply-context").classList.add("hidden");

  // Move input area back to the bottom of post section
  const postSection = $("post-section");
  const inputArea = $("post-input-area");
  postSection.appendChild(inputArea);
}

async function handleReaction(
  postPath: string,
  reactionKey: string,
  currentReactions: Record<string, string[]>,
): Promise<void> {
  const { token, username } = store.state;
  if (!token || !username) return;

  const newReactions = { ...currentReactions };
  const users = newReactions[reactionKey] ? [...newReactions[reactionKey]] : [];
  const idx = users.indexOf(username);
  if (idx >= 0) {
    users.splice(idx, 1);
  } else {
    users.push(username);
  }
  newReactions[reactionKey] = users;

  try {
    // postPath is the full DB path like /v1/m3ssag1n8/ws/channels/ch/posts/id
    await patchReactions(token, postPath, newReactions);
  } catch (e) {
    slog.warn("Failed to update reaction", ["error", e]);
  }
}

function renderPost(post: Post, byParent: Map<string, Post[]>): HTMLElement {
  const { username } = store.state;
  const reactions = (post.doc.reactions ?? {}) as Record<string, string[]>;

  const div = document.createElement("div");
  div.className = "post-item";
  div.dataset["path"] = post.path;

  const reactionHtml = REACTIONS.map((r) => {
    const users = reactions[r.key] ?? [];
    const count = users.length;
    const reacted = username ? users.includes(username) : false;
    return `<button
        class="reaction-btn${reacted ? " reacted" : ""}"
        data-reaction="${r.key}"
        aria-label="${r.label} (${count})"
        title="${r.key}"
      >
        <iconify-icon icon="${r.icon}" aria-label="${r.label}"></iconify-icon>
        <span class="reaction-count">${count}</span>
      </button>`;
  }).join("");

  div.innerHTML = `
    <div class="post-header-row">
      <span class="post-author">${escapeHtml(post.meta.createdBy || "unknown")}</span>
      <span class="post-time">${formatTime(post.meta.createdAt)}</span>
    </div>
    <div class="post-content">${renderMarkdown(post.doc.msg)}</div>
    <div class="post-actions">
      <button class="reply-btn" data-action="reply" aria-label="Reply to post">
        <iconify-icon icon="mdi:reply" aria-label="reply"></iconify-icon> Reply
      </button>
      ${reactionHtml}
    </div>
    <div class="replies"></div>
  `;

  // Reply button
  div.querySelector<HTMLButtonElement>('[data-action="reply"]')!
    .addEventListener("click", (e) => {
      e.stopPropagation();
      startReply(post.path, post.doc.msg);
    });

  // Reaction buttons
  div.querySelectorAll<HTMLButtonElement>(".reaction-btn").forEach((btn) => {
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      const key = btn.dataset["reaction"] ?? "";
      handleReaction(post.path, key, reactions);
    });
  });

  // Render nested replies
  const replies = byParent.get(post.path) ?? [];
  if (replies.length > 0) {
    const repliesDiv = div.querySelector(".replies")!;
    for (const reply of replies) {
      repliesDiv.appendChild(renderPost(reply, byParent));
    }
  }

  return div;
}

function renderPosts(): void {
  const { posts, currentChannel } = store.state;
  const postList = $("post-list");

  if (!currentChannel) {
    postList.innerHTML = '<p class="empty-state">Open a channel to see messages.</p>';
    return;
  }

  const allPosts = Array.from(posts.values());
  allPosts.sort((a, b) => {
    const ta = a.meta.createdAt;
    const tb = b.meta.createdAt;
    return ta < tb ? -1 : ta > tb ? 1 : 0;
  });

  const topLevel: Post[] = [];
  const byParent = new Map<string, Post[]>();

  for (const post of allPosts) {
    const parent = post.doc.parent ?? "";
    if (!parent) {
      topLevel.push(post);
    } else {
      if (!byParent.has(parent)) byParent.set(parent, []);
      byParent.get(parent)!.push(post);
    }
  }

  // Preserve input area position
  const postSection = $("post-section");
  const inputArea = $("post-input-area");

  postList.innerHTML = "";

  if (topLevel.length === 0) {
    postList.innerHTML = '<p class="empty-state">No messages yet.</p>';
  } else {
    for (const post of topLevel) {
      postList.appendChild(renderPost(post, byParent));
    }
  }

  // If not in reply mode, keep input at bottom
  if (!replyToPath) {
    postSection.appendChild(inputArea);
  }
}

// ---------------------------------------------------------------------------
// State subscription — react to state changes and update the UI
// ---------------------------------------------------------------------------

function subscribeToStateChanges(): void {
  store.addEventListener("state-change", () => {
    const { currentWorkspace, currentChannel } = store.state;

    // Workspace sidebar visibility
    const channelSidebar = $("channel-sidebar");
    if (currentWorkspace) {
      channelSidebar.classList.remove("hidden");
      $("current-workspace-label").textContent = currentWorkspace;
    } else {
      channelSidebar.classList.add("hidden");
      $("current-workspace-label").textContent = "";
    }

    // Post section visibility
    const postSection = $("post-section");
    if (currentChannel) {
      postSection.classList.remove("hidden");
      $("current-channel-label").textContent = currentChannel;
    } else {
      postSection.classList.add("hidden");
      $("current-channel-label").textContent = "";
    }

    renderWorkspaceList();
    renderChannelList();
    renderPosts();
  });
}

