function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

/* Register event handler to run after the page is fully loaded. */
document.addEventListener("DOMContentLoaded", () => {
  main();
});

/**
 * Minimal markdown formatter for posts.
 * Converts: **bold**, *italic*, [text](url), :reaction:, and \n to <br>.
 */

/** Map of supported reaction names to iconify icon names. */
const REACTION_ICONS: Record<string, string> = {
  ":smile:": "mdi:emoticon-happy-outline",
  ":frown:": "mdi:emoticon-sad-outline",
  ":like:": "mdi:thumb-up-outline",
  ":celebrate:": "mdi:party-popper",
};

/**
 * Render a plain-text post message as safe HTML with markdown formatting.
 * Returns an HTML string — caller must set innerHTML.
 */
export function renderMarkdown(text: string): string {
  // Escape HTML special chars first (prevent XSS)
  let html = escapeHtml(text);

  // Replace **bold** with <strong>
  html = html.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");

  // Replace *italic* with <em>
  html = html.replace(/\*([^*]+)\*/g, "<em>$1</em>");

  // Replace [text](url) with <a href="url">text</a>
  // Only allow http/https URLs
  html = html.replace(
    /\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g,
    '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>',
  );

  // Replace :reaction: with iconify icons (for known reactions)
  html = html.replace(/:([a-z][a-z-]*):/g, (match) => {
    const icon = REACTION_ICONS[match];
    if (icon) {
      return `<iconify-icon icon="${icon}" aria-label="${match}" class="inline-icon"></iconify-icon>`;
    }
    return match; // unknown reaction — leave as-is
  });

  // Convert \n to <br>
  html = html.replace(/\n/g, "<br>");

  return html;
}

/** HTML-escape a string to prevent XSS. */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

/** Format a timestamp for display. Accepts ISO string or Unix ms number. */
export function formatTime(ts: string | number): string {
  if (!ts && ts !== 0) return "";
  try {
    const d = typeof ts === "number" ? new Date(ts) : new Date(ts);
    return d.toLocaleString();
  } catch {
    return String(ts);
  }
}

/**
 * OwlDB API client — all HTTP/SSE calls to the database.
 */

import { fetchEventSource } from "@microsoft/fetch-event-source";
import { slog } from "./slog";
import {
  isAuthResponse,
  isCollection,
  isPostCreateResponse,
  PostDoc,
  nameFromPath,
  Workspace,
  Channel,
  isPostDoc,
} from "./types";

declare const process: {
  env: { DATABASE_HOST: string; DATABASE_PATH: string; AUTH_PATH: string };
};

export const DB_HOST = process.env.DATABASE_HOST;
export const DB_PATH = process.env.DATABASE_PATH;
export const AUTH_PATH_ENV = process.env.AUTH_PATH;

/** Full base URL for the database (ends with /). */
export const DB_URL = `${DB_HOST}${DB_PATH}`;
/** Full URL for auth endpoint. */
export const AUTH_URL = `${DB_HOST}${AUTH_PATH_ENV}`;

// ---------------------------------------------------------------------------
// Auth
// ---------------------------------------------------------------------------

/** Login with username. Returns bearer token. */
export async function login(username: string): Promise<string> {
  const res = await fetch(AUTH_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username }),
  });
  if (!res.ok) {
    throw new Error(`Login failed: ${res.status} ${res.statusText}`);
  }
  const data: unknown = await res.json();
  if (!isAuthResponse(data)) throw new Error("Invalid auth response from server");
  return data.token;
}

/** Logout — destroys the bearer token on the server. */
export async function logout(token: string): Promise<void> {
  const res = await fetch(AUTH_URL, {
    method: "DELETE",
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!res.ok && res.status !== 204) {
    slog.warn("Logout request failed", ["status", res.status]);
  }
}

// ---------------------------------------------------------------------------
// Workspaces
// ---------------------------------------------------------------------------

/** List all workspaces in the database. */
export async function listWorkspaces(token: string): Promise<Workspace[]> {
  const res = await fetch(DB_URL, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!res.ok) throw new Error(`Failed to list workspaces: ${res.status}`);
  const data: unknown = await res.json();
  if (!isCollection(data)) {
    slog.warn("Unexpected workspace listing format, treating as empty");
    return [];
  }
  return data.map((d) => ({
    path: d.path,
    name: nameFromPath(d.path),
  }));
}

/** Create a new workspace. Throws on error (e.g., 409 conflict). */
export async function createWorkspace(token: string, name: string): Promise<void> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(name)}`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
  if (!res.ok) {
    const msg = res.status === 409 ? "Workspace already exists" : `Error ${res.status}`;
    throw new Error(msg);
  }
  // Create the channels/ collection inside the workspace
  await fetch(`${DB_URL}${encodeURIComponent(name)}/channels/`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
}

/** Open (load) a workspace by fetching its channels. Throws if not found. */
export async function openWorkspace(token: string, name: string): Promise<Channel[]> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(name)}/channels/`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (res.status === 404) throw new Error(`Workspace "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to open workspace: ${res.status}`);
  const data: unknown = await res.json();
  if (!isCollection(data)) {
    slog.warn("Unexpected channels format");
    return [];
  }
  return data.map((d) => ({
    path: d.path,
    name: nameFromPath(d.path),
  }));
}

/** Delete a workspace. Throws if not found. */
export async function deleteWorkspace(token: string, name: string): Promise<void> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(name)}`, {
    method: "DELETE",
    headers: { Authorization: `Bearer ${token}` },
  });
  if (res.status === 404) throw new Error(`Workspace "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to delete workspace: ${res.status}`);
}

