// Channels
// ---------------------------------------------------------------------------

/** List channels in a workspace. */
export async function listChannels(token: string, workspace: string): Promise<Channel[]> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(workspace)}/channels/`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!res.ok) throw new Error(`Failed to list channels: ${res.status}`);
  const data: unknown = await res.json();
  if (!isCollection(data)) return [];
  return data.map((d) => ({
    path: d.path,
    name: nameFromPath(d.path),
  }));
}

/** Create a new channel in a workspace. */
export async function createChannel(
  token: string,
  workspace: string,
  name: string,
): Promise<void> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}`,
    {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({}),
    },
  );
  if (!res.ok) {
    const msg = res.status === 409 ? "Channel already exists" : `Error ${res.status}`;
    throw new Error(msg);
  }
  // Create posts/ collection
  await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}/posts/`,
    {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({}),
    },
  );
}

/** Open a channel — verifies it exists and returns a confirmation. */
export async function openChannel(
  token: string,
  workspace: string,
  name: string,
): Promise<void> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}/posts/`,
    {
      headers: { Authorization: `Bearer ${token}` },
    },
  );
  if (res.status === 404) throw new Error(`Channel "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to open channel: ${res.status}`);
}

/** Delete a channel from a workspace. */
export async function deleteChannel(
  token: string,
  workspace: string,
  name: string,
): Promise<void> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}`,
    {
      method: "DELETE",
      headers: { Authorization: `Bearer ${token}` },
    },
  );
  if (res.status === 404) throw new Error(`Channel "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to delete channel: ${res.status}`);
}

// ---------------------------------------------------------------------------
// Posts
// ---------------------------------------------------------------------------

/** Create a post in a channel. Returns the created document URI. */
export async function createPost(
  token: string,
  workspace: string,
  channel: string,
  msg: string,
  parent: string = "",
): Promise<string> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
    {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ msg, parent }),
    },
  );
  if (!res.ok) throw new Error(`Failed to create post: ${res.status}`);
  const data: unknown = await res.json();
  if (!isPostCreateResponse(data)) throw new Error("Invalid post create response");
  return data.uri;
}

/** Update a post's reactions via PATCH. */
export async function patchReactions(
  token: string,
  postFullPath: string,
  reactions: Record<string, string[]>,
): Promise<void> {
  const url = `${DB_HOST}${postFullPath}`;
  const res = await fetch(url, {
    method: "PATCH",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify([
      { op: "ObjectAdd", path: "/reactions", value: reactions },
    ]),
  });
  if (!res.ok) throw new Error(`Failed to patch reactions: ${res.status}`);
}

// ---------------------------------------------------------------------------
// SSE subscription
// ---------------------------------------------------------------------------

export interface SSEPostEvent {
  eventType: "put" | "patch" | "delete";
  path: string;
  doc?: PostDoc;
  meta?: { createdAt: string; createdBy: string };
}

/**
 * Subscribe to live post updates via Server-Sent Events.
 * Calls onPost for each received post event.
 * Returns an AbortController you can use to unsubscribe.
 */
export function subscribeToChannel(
  token: string,
  workspace: string,
  channel: string,
  onPost: (event: SSEPostEvent) => void,
  onError?: (err: unknown) => void,
): AbortController {
  const controller = new AbortController();
  const url = `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/?mode=subscribe`;

  fetchEventSource(url, {
    headers: { Authorization: `Bearer ${token}` },
    signal: controller.signal,
    onmessage(ev) {
      try {
        const data: unknown = JSON.parse(ev.data);
        if (typeof data !== "object" || data === null) return;

        const d = data as Record<string, unknown>;
        const path = typeof d["path"] === "string" ? d["path"] : "";
        const rawDoc = d["doc"];
        const rawMeta = d["meta"];

        // OwlDB sends event type "update" (initial snapshot + patches) or "delete"
        let eventType: "put" | "patch" | "delete" = "put";
        if (ev.event === "delete") {
          eventType = "delete";
        } else {
          // "update" covers both initial snapshot and live updates
          eventType = "put";
        }

        const doc = isPostDoc(rawDoc) ? rawDoc : undefined;
        const meta =
          rawMeta &&
          typeof rawMeta === "object" &&
          "createdAt" in rawMeta &&
          "createdBy" in rawMeta
            ? {
                createdAt: String((rawMeta as Record<string, unknown>)["createdAt"]),
                createdBy: String((rawMeta as Record<string, unknown>)["createdBy"]),
              }
            : undefined;

        onPost({ eventType, path, doc, meta });
      } catch (e) {
        slog.warn("Failed to parse SSE event", ["error", e]);
      }
    },
    onerror(err) {
      slog.warn("SSE error", ["err", err]);
      if (onError) onError(err);
      throw err; // stop retrying on persistent error
    },
  }).catch((e) => {
    // Absorb AbortError from controller.abort()
    if (e instanceof DOMException && e.name === "AbortError") return;
    slog.warn("SSE connection error", ["error", e]);
  });

  return controller;
}

/**
 * JSON schemas, TypeScript types, and AJV validators for OwlDB API data.
 */

import type { JSONSchema } from "json-schema-to-ts";
import { FromSchema } from "json-schema-to-ts";
import { $Compiler, wrapCompilerAsTypeGuard } from "json-schema-to-ts";
import Ajv from "ajv";

/** Single AJV instance for all schema compilation. */
const ajv = new Ajv();
const $compile: $Compiler = (schema) => ajv.compile(schema);
const compile = wrapCompilerAsTypeGuard($compile);

// ---------------------------------------------------------------------------
// Auth
// ---------------------------------------------------------------------------

export const AuthResponseSchema = {
  $id: "auth-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "AuthResponse",
  type: "object",
  required: ["token"],
  properties: {
    token: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type AuthResponse = FromSchema<typeof AuthResponseSchema>;
export const isAuthResponse = compile(AuthResponseSchema);

// ---------------------------------------------------------------------------
// Post document
// ---------------------------------------------------------------------------

export const PostDocSchema = {
  $id: "post-doc.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "PostDoc",
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: {
      type: "object",
      additionalProperties: {
        type: "array",
        items: { type: "string" },
      },
    },
    extensions: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type PostDoc = FromSchema<typeof PostDocSchema>;
export const isPostDoc = compile(PostDocSchema);

// ---------------------------------------------------------------------------
// Generic database document (returned in collection listings)
// ---------------------------------------------------------------------------

export const DbDocSchema = {
  $id: "db-doc.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "DbDoc",
  type: "object",
  required: ["path", "doc"],
  properties: {
    path: { type: "string" },
    doc: { type: "object", additionalProperties: true },
    meta: {
      type: "object",
      properties: {
        createdAt: { type: ["string", "number"] },
        createdBy: { type: "string" },
        lastModifiedAt: { type: ["string", "number"] },
        lastModifiedBy: { type: "string" },
      },
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type DbDoc = FromSchema<typeof DbDocSchema>;
export const isDbDoc = compile(DbDocSchema);

// ---------------------------------------------------------------------------
// Collection (array of documents)
// ---------------------------------------------------------------------------

export const CollectionSchema = {
  $id: "collection.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Collection",
  type: "array",
  items: {
    type: "object",
    required: ["path", "doc"],
    properties: {
      path: { type: "string" },
      doc: { type: "object", additionalProperties: true },
      meta: {
        type: "object",
        properties: {
          createdAt: { type: ["string", "number"] },
          createdBy: { type: "string" },
        },
        additionalProperties: true,
      },
    },
    additionalProperties: true,
  },
} as const satisfies JSONSchema;

export type Collection = FromSchema<typeof CollectionSchema>;
export const isCollection = compile(CollectionSchema);

// ---------------------------------------------------------------------------
// Post create response
// ---------------------------------------------------------------------------

export const PostCreateResponseSchema = {
  $id: "post-create-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "PostCreateResponse",
  type: "object",
  required: ["uri"],
  properties: {
    uri: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type PostCreateResponse = FromSchema<typeof PostCreateResponseSchema>;
export const isPostCreateResponse = compile(PostCreateResponseSchema);

// ---------------------------------------------------------------------------
// Application domain types
// ---------------------------------------------------------------------------

export interface PostMeta {
  createdAt: string | number;
  createdBy: string;
}

export interface Post {
  path: string;
  doc: PostDoc;
  meta: PostMeta;
}

export interface Workspace {
  path: string;
  name: string;
}

export interface Channel {
  path: string;
  name: string;
}

/** Extract the last path segment as a name (URL-decoded). */
export function nameFromPath(path: string): string {
  const parts = path.split("/").filter(Boolean);
  const last = parts[parts.length - 1] ?? "";
  try {
    return decodeURIComponent(last);
  } catch {
    return last;
  }
}

